     1→'use client';
     2→
     3→import { useCallback, useEffect, useRef, useState } from 'react';
     4→import { useSearchParams, useRouter, usePathname } from 'next/navigation';
     5→import { useTranslation } from 'react-i18next';
     6→import {
     7→  fetchBalanceSummary,
     8→  createTenantAccount,
     9→  useCurrencyStore,
    10→  SALARY_CURRENCIES,
    11→  CURRENCY_SYMBOLS,
    12→  type BalanceSummaryDto,
    13→  type TenantAccountBalanceSummaryDto,
    14→  type SalaryCurrency,
    15→} from '@/entities/balance';
    16→import { AccountsHeader, type AccountTab } from './AccountsHeader';
    17→import { AccountTable } from './AccountTable';
    18→import { TransactionHistory } from './TransactionHistory';
    19→import { WithdrawalModal } from './WithdrawalModal';
    20→import { InvoiceModal } from './InvoiceModal';
    21→import './accounts-page.scss';
    22→
    23→function getAccountTotal(
    24→  account: TenantAccountBalanceSummaryDto,
    25→  currency: SalaryCurrency,
    26→): string {
    27→  switch (currency) {
    28→    case 'USD': return account.totalUSD;
    29→    case 'EUR': return account.totalEUR;
    30→    case 'RUB': return account.totalRUB;
    31→  }
    32→}
    33→
    34→function formatTotal(value: string, currency: SalaryCurrency): string {
    35→  const num = parseFloat(value);
    36→  if (isNaN(num)) return `${CURRENCY_SYMBOLS[currency]}0`;
    37→  return `${CURRENCY_SYMBOLS[currency]}${new Intl.NumberFormat('en-US', {
    38→    minimumFractionDigits: 0,
    39→    maximumFractionDigits: 0,
    40→  }).format(num)}`;
    41→}
    42→
    43→export default function AccountsPage() {
    44→  const { t } = useTranslation('accounts');
    45→  const router = useRouter();
    46→  const pathname = usePathname();
    47→  const searchParams = useSearchParams();
    48→
    49→  const [data, setData] = useState<BalanceSummaryDto | null>(null);
    50→  const [selectedAccountId, setSelectedAccountId] = useState<string | null>(null);
    51→  const currency = useCurrencyStore((s) => s.currency);
    52→  const setCurrency = useCurrencyStore((s) => s.setCurrency);
    53→  const [loading, setLoading] = useState(true);
    54→  const [withdrawOpen, setWithdrawOpen] = useState(false);
    55→  const [invoiceOpen, setInvoiceOpen] = useState(false);
    56→
    57→  const tabParam = searchParams.get('tab');
    58→  const activeTab: AccountTab = tabParam === 'history' ? 'history' : 'balances';
    59→
    60→  const searchParamsRef = useRef(searchParams);
    61→  searchParamsRef.current = searchParams;
    62→
    63→  const setActiveTab = useCallback((tab: AccountTab) => {
    64→    const params = new URLSearchParams(searchParamsRef.current.toString());
    65→    if (tab === 'balances') {
    66→      params.delete('tab');
    67→      params.delete('type');
    68→      params.delete('status');
    69→      params.delete('search');
    70→      params.delete('page');
    71→    } else {
    72→      params.set('tab', tab);
    73→    }
    74→    const qs = params.toString();
    75→    router.replace(qs ? `${pathname}?${qs}` : pathname, { scroll: false });
    76→  }, [router, pathname]);
    77→
    78→  const loadData = useCallback(async () => {
    79→    try {
    80→      const res = await fetchBalanceSummary();
    81→      setData(res);
    82→      return res;
    83→    } catch {
    84→      return null;
    85→    }
    86→  }, []);
    87→
    88→  useEffect(() => {
    89→    let cancelled = false;
    90→    fetchBalanceSummary()
    91→      .then((res) => {
    92→        if (cancelled) return;
    93→        setData(res);
    94→        if (res.accounts.length > 0) {
    95→          setSelectedAccountId(res.accounts[0].tenantAccountId);
    96→        }
    97→      })
    98→      .catch(() => {})
    99→      .finally(() => {
   100→        if (!cancelled) setLoading(false);
   101→      });
   102→    return () => { cancelled = true; };
   103→  }, []);
   104→
   105→  const handleCreate = useCallback(async (name: string) => {
   106→    const created = await createTenantAccount(name);
   107→    const refreshed = await loadData();
   108→    if (refreshed) {
   109→      const newAccount = refreshed.accounts.find(
   110→        (a) => a.tenantAccountId === created.id,
   111→      );
   112→      if (newAccount) {
   113→        setSelectedAccountId(newAccount.tenantAccountId);
   114→      }
   115→    }
   116→  }, [loadData]);
   117→
   118→  const selectedAccount =
   119→    data?.accounts.find((a) => a.tenantAccountId === selectedAccountId) ?? null;
   120→
   121→  const accountCount = data?.accounts.length ?? 0;
   122→  const assetCount = selectedAccount?.balances.length ?? 0;
   123→  const totalDisplay = selectedAccount
   124→    ? formatTotal(getAccountTotal(selectedAccount, currency), currency)
   125→    : '—';
   126→
   127→  const handleCurrencyCycle = useCallback(() => {
   128→    const idx = SALARY_CURRENCIES.indexOf(currency);
   129→    setCurrency(SALARY_CURRENCIES[(idx + 1) % SALARY_CURRENCIES.length]);
   130→  }, [currency, setCurrency]);
   131→
   132→  return (
   133→    <div className="accounts-page">
   134→      <AccountsHeader
   135→        accountCount={accountCount}
   136→        accounts={data?.accounts ?? []}
   137→        selectedAccountId={selectedAccountId}
   138→        onAccountChange={setSelectedAccountId}
   139→        onCreate={handleCreate}
   140→        activeTab={activeTab}
   141→        onTabChange={setActiveTab}
   142→      />
   143→
   144→      {activeTab === 'balances' && (
   145→        <>
   146→          {/* Balance Summary Card — desktop only */}
   147→          <div className="balance-summary">
   148→            <div className="balance-summary__left">
   149→              <span className="balance-summary__label">{t('totalBalance')}</span>
   150→              <div className="balance-summary__amount">
   151→                <span className="balance-summary__value">{totalDisplay}</span>
   152→                <span className="balance-summary__currency-label">{currency}</span>
   153→              </div>
   154→              <span className="balance-summary__subtitle">
   155→                {t('acrossAssets', { count: assetCount })}
   156→                {' · '}
   157→                {t('displayCurrency')}:&nbsp;
   158→                <button
   159→                  type="button"
   160→                  className="balance-summary__currency-switch"
   161→                  onClick={handleCurrencyCycle}
   162→                >
   163→                  {currency}
   164→                </button>
   165→              </span>
   166→            </div>
   167→            <div className="balance-summary__actions">
   168→              <button
   169→                type="button"
   170→                className="balance-summary__action-btn"
   171→                onClick={() => setInvoiceOpen(true)}
   172→              >
   173→                {t('createInvoice')}
   174→              </button>
   175→              <button type="button" className="balance-summary__action-btn">
   176→                {t('addFunds')}
   177→              </button>
   178→              <button
   179→                type="button"
   180→                className="balance-summary__action-btn"
   181→                onClick={() => setWithdrawOpen(true)}
   182→              >
   183→                {t('withdraw')}
   184→              </button>
   185→            </div>
   186→          </div>
   187→
   188→          <AccountTable
   189→            account={selectedAccount}
   190→            currency={currency}
   191→            onCurrencyChange={setCurrency}
   192→            loading={loading}
   193→          />
   194→        </>
   195→      )}
   196→
   197→      {activeTab === 'history' && <TransactionHistory tenantAccountId={selectedAccountId} />}
   198→
   199→      {invoiceOpen && selectedAccount && (
   200→        <InvoiceModal
   201→          tenantAccountId={selectedAccount.tenantAccountId}
   202→          onClose={() => setInvoiceOpen(false)}
   203→        />
   204→      )}
   205→
   206→      {withdrawOpen && selectedAccount && (
   207→        <WithdrawalModal
   208→          tenantAccountId={selectedAccount.tenantAccountId}
   209→          balances={selectedAccount.balances}
   210→          onClose={() => {
   211→            setWithdrawOpen(false);
   212→            loadData();
   213→          }}
   214→        />
   215→      )}
   216→    </div>
   217→  );
   218→}
