     1→'use client';
     2→
     3→import { useCallback, useEffect, useLayoutEffect, useRef, useState } from 'react';
     4→import { useTranslation } from 'react-i18next';
     5→import type { TenantAccountBalanceSummaryDto } from '@/entities/balance';
     6→import {
     7→  Modal,
     8→  ModalTitle,
     9→  ModalLabel,
    10→  ModalError,
    11→  ModalActions,
    12→  ModalButton,
    13→} from '@/shared/ui';
    14→import './accounts-header.scss';
    15→
    16→export type AccountTab = 'balances' | 'history';
    17→
    18→interface AccountsHeaderProps {
    19→  accounts: TenantAccountBalanceSummaryDto[];
    20→  selectedAccountId: string | null;
    21→  onAccountChange: (id: string) => void;
    22→  onCreate: (name: string) => Promise<void>;
    23→  accountCount: number;
    24→  activeTab: AccountTab;
    25→  onTabChange: (tab: AccountTab) => void;
    26→}
    27→
    28→function AccountAvatar({ name }: { name: string }) {
    29→  const letter = name.charAt(0).toUpperCase();
    30→  return <span className="accounts-header__avatar">{letter}</span>;
    31→}
    32→
    33→const MAX_ACCOUNTS = 3;
    34→
    35→export function AccountsHeader({
    36→  accounts,
    37→  selectedAccountId,
    38→  onAccountChange,
    39→  onCreate,
    40→  accountCount,
    41→  activeTab,
    42→  onTabChange,
    43→}: AccountsHeaderProps) {
    44→  const { t } = useTranslation('accounts');
    45→  const [dropdownOpen, setDropdownOpen] = useState(false);
    46→  const [modalOpen, setModalOpen] = useState(false);
    47→  const [accountName, setAccountName] = useState('');
    48→  const [creating, setCreating] = useState(false);
    49→  const [error, setError] = useState('');
    50→  const desktopDropdownRef = useRef<HTMLDivElement>(null);
    51→  const mobileDropdownRef = useRef<HTMLDivElement>(null);
    52→  const inputRef = useRef<HTMLInputElement>(null);
    53→  const tabsRef = useRef<HTMLElement>(null);
    54→  const tabRefs = useRef<Record<AccountTab, HTMLButtonElement | null>>({ balances: null, history: null });
    55→  const [indicator, setIndicator] = useState({ left: 0, width: 0 });
    56→
    57→  const mobileTabsRef = useRef<HTMLElement>(null);
    58→  const mobileTabRefs = useRef<Record<AccountTab, HTMLButtonElement | null>>({ balances: null, history: null });
    59→  const [mobileIndicator, setMobileIndicator] = useState({ left: 0, width: 0 });
    60→
    61→  const selectedAccount = accounts.find(
    62→    (a) => a.tenantAccountId === selectedAccountId,
    63→  );
    64→
    65→  useLayoutEffect(() => {
    66→    const btn = tabRefs.current[activeTab];
    67→    const nav = tabsRef.current;
    68→    if (btn && nav) {
    69→      const navRect = nav.getBoundingClientRect();
    70→      const btnRect = btn.getBoundingClientRect();
    71→      setIndicator({ left: btnRect.left - navRect.left, width: btnRect.width });
    72→    }
    73→
    74→    const mBtn = mobileTabRefs.current[activeTab];
    75→    const mNav = mobileTabsRef.current;
    76→    if (mBtn && mNav) {
    77→      const navRect = mNav.getBoundingClientRect();
    78→      const btnRect = mBtn.getBoundingClientRect();
    79→      setMobileIndicator({ left: btnRect.left - navRect.left, width: btnRect.width });
    80→    }
    81→  }, [activeTab]);
    82→
    83→  useEffect(() => {
    84→    function onPointerDown(e: PointerEvent) {
    85→      const target = e.target as Node;
    86→      if (!desktopDropdownRef.current?.contains(target) && !mobileDropdownRef.current?.contains(target)) {
    87→        setDropdownOpen(false);
    88→      }
    89→    }
    90→    document.addEventListener('pointerdown', onPointerDown);
    91→    return () => document.removeEventListener('pointerdown', onPointerDown);
    92→  }, []);
    93→
    94→  useEffect(() => {
    95→    if (modalOpen) {
    96→      requestAnimationFrame(() => inputRef.current?.focus());
    97→    }
    98→  }, [modalOpen]);
    99→
   100→  const openModal = useCallback(() => {
   101→    setAccountName('');
   102→    setError('');
   103→    setModalOpen(true);
   104→  }, []);
   105→
   106→  const closeModal = useCallback(() => {
   107→    if (creating) return;
   108→    setModalOpen(false);
   109→  }, [creating]);
   110→
   111→  const handleSubmit = useCallback(async () => {
   112→    const trimmed = accountName.trim();
   113→    if (!trimmed || creating) return;
   114→
   115→    setCreating(true);
   116→    setError('');
   117→    try {
   118→      await onCreate(trimmed);
   119→      setModalOpen(false);
   120→    } catch (err: unknown) {
   121→      const message =
   122→        err instanceof Error ? err.message : t('createModal.maxReached');
   123→      setError(message);
   124→    } finally {
   125→      setCreating(false);
   126→    }
   127→  }, [accountName, creating, onCreate, t]);
   128→
   129→  const atLimit = accountCount >= MAX_ACCOUNTS;
   130→
   131→  return (
   132→    <>
   133→      {/* Desktop Header */}
   134→      <div className="accounts-header">
   135→        <div className="accounts-header__left">
   136→          <h1 className="accounts-header__title">{t('title')}</h1>
   137→          <nav ref={tabsRef} className="accounts-header__tabs">
   138→            <button
   139→              ref={(el) => { tabRefs.current.balances = el; }}
   140→              type="button"
   141→              className={`accounts-header__tab${activeTab === 'balances' ? ' accounts-header__tab--active' : ''}`}
   142→              onClick={() => onTabChange('balances')}
   143→            >
   144→              {t('tabs.balances')}
   145→            </button>
   146→            <button
   147→              ref={(el) => { tabRefs.current.history = el; }}
   148→              type="button"
   149→              className={`accounts-header__tab${activeTab === 'history' ? ' accounts-header__tab--active' : ''}`}
   150→              onClick={() => onTabChange('history')}
   151→            >
   152→              {t('tabs.history')}
   153→            </button>
   154→            <span
   155→              className="accounts-header__tab-indicator"
   156→              style={{ left: indicator.left, width: indicator.width }}
   157→            />
   158→          </nav>
   159→        </div>
   160→
   161→        <div className="accounts-header__right">
   162→          <div ref={desktopDropdownRef} className="accounts-header__dropdown-wrap">
   163→            <button
   164→              type="button"
   165→              className={`accounts-header__dropdown${dropdownOpen ? ' accounts-header__dropdown--open' : ''}`}
   166→              onClick={() => setDropdownOpen((v) => !v)}
   167→            >
   168→              <span className="accounts-header__avatar">{accountCount}</span>
   169→              <span className="accounts-header__dropdown-text">
   170→                {selectedAccount?.tenantAccountName ?? '—'}
   171→              </span>
   172→              <svg
   173→                className={`accounts-header__dropdown-chevron${dropdownOpen ? ' accounts-header__dropdown-chevron--open' : ''}`}
   174→                width="16"
   175→                height="16"
   176→                viewBox="0 0 16 16"
   177→                fill="none"
   178→              >
   179→                <path
   180→                  d="M4 6L8 10L12 6"
   181→                  stroke="currentColor"
   182→                  strokeWidth="1.5"
   183→                  strokeLinecap="round"
   184→                  strokeLinejoin="round"
   185→                />
   186→              </svg>
   187→            </button>
   188→            {dropdownOpen && (
   189→              <ul className="accounts-header__dropdown-menu">
   190→                {accounts.map((acc) => (
   191→                  <li key={acc.tenantAccountId}>
   192→                    <button
   193→                      type="button"
   194→                      className={`accounts-header__dropdown-option${
   195→                        acc.tenantAccountId === selectedAccountId
   196→                          ? ' accounts-header__dropdown-option--active'
   197→                          : ''
   198→                      }`}
   199→                      onClick={() => {
   200→                        onAccountChange(acc.tenantAccountId);
   201→                        setDropdownOpen(false);
   202→                      }}
   203→                    >
   204→                      <AccountAvatar name={acc.tenantAccountName} />
   205→                      {acc.tenantAccountName}
   206→                    </button>
   207→                  </li>
   208→                ))}
   209→                {!atLimit && (
   210→                  <li className="accounts-header__dropdown-divider" />
   211→                )}
   212→                {!atLimit && (
   213→                  <li>
   214→                    <button
   215→                      type="button"
   216→                      className="accounts-header__dropdown-option accounts-header__dropdown-option--create"
   217→                      onClick={() => {
   218→                        setDropdownOpen(false);
   219→                        openModal();
   220→                      }}
   221→                    >
   222→                      <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
   223→                        <path d="M8 3V13M3 8H13" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
   224→                      </svg>
   225→                      {t('createModal.title')}
   226→                    </button>
   227→                  </li>
   228→                )}
   229→              </ul>
   230→            )}
   231→          </div>
   232→
   233→        </div>
   234→      </div>
   235→
   236→      {/* Mobile Header */}
   237→      <div className="accounts-header-mobile">
   238→        <div className="accounts-header-mobile__top">
   239→          <span className="accounts-header-mobile__badge">
   240→            {t('accountCount', { count: accountCount })}
   241→          </span>
   242→        </div>
   243→
   244→        <div ref={mobileDropdownRef} className="accounts-header-mobile__dropdown-wrap">
   245→          <button
   246→            type="button"
   247→            className="accounts-header-mobile__dropdown"
   248→            onClick={() => setDropdownOpen((v) => !v)}
   249→          >
   250→            <span className="accounts-header-mobile__account-name">
   251→              {selectedAccount?.tenantAccountName ?? '—'}
   252→            </span>
   253→            <svg
   254→              className={`accounts-header-mobile__arrow${dropdownOpen ? ' accounts-header-mobile__arrow--open' : ''}`}
   255→              width="20"
   256→              height="20"
   257→              viewBox="0 0 16 16"
   258→              fill="none"
   259→            >
   260→              <path
   261→                d="M4 6L8 10L12 6"
   262→                stroke="currentColor"
   263→                strokeWidth="1.5"
   264→                strokeLinecap="round"
   265→                strokeLinejoin="round"
   266→              />
   267→            </svg>
   268→          </button>
   269→          {dropdownOpen && (
   270→            <ul className="accounts-header-mobile__dropdown-menu">
   271→              {accounts.map((acc) => (
   272→                <li key={acc.tenantAccountId}>
   273→                  <button
   274→                    type="button"
   275→                    className={`accounts-header-mobile__dropdown-option${
   276→                      acc.tenantAccountId === selectedAccountId
   277→                        ? ' accounts-header-mobile__dropdown-option--active'
   278→                        : ''
   279→                    }`}
   280→                    onClick={() => {
   281→                      onAccountChange(acc.tenantAccountId);
   282→                      setDropdownOpen(false);
   283→                    }}
   284→                  >
   285→                    {acc.tenantAccountName}
   286→                  </button>
   287→                </li>
   288→              ))}
   289→            </ul>
   290→          )}
   291→        </div>
   292→
   293→        <p className="accounts-header-mobile__subtitle">{t('subtitle')}</p>
   294→
   295→        <nav ref={mobileTabsRef} className="accounts-header-mobile__tabs">
   296→          <button
   297→            ref={(el) => { mobileTabRefs.current.balances = el; }}
   298→            type="button"
   299→            className={`accounts-header-mobile__tab${activeTab === 'balances' ? ' accounts-header-mobile__tab--active' : ''}`}
   300→            onClick={() => onTabChange('balances')}
   301→          >
   302→            {t('tabs.balances')}
   303→          </button>
   304→          <button
   305→            ref={(el) => { mobileTabRefs.current.history = el; }}
   306→            type="button"
   307→            className={`accounts-header-mobile__tab${activeTab === 'history' ? ' accounts-header-mobile__tab--active' : ''}`}
   308→            onClick={() => onTabChange('history')}
   309→          >
   310→            {t('tabs.history')}
   311→          </button>
   312→          <span
   313→            className="accounts-header-mobile__tab-indicator"
   314→            style={{ left: mobileIndicator.left, width: mobileIndicator.width }}
   315→          />
   316→        </nav>
   317→      </div>
   318→
   319→      {/* Mobile FAB */}
   320→      <button
   321→        type="button"
   322→        className="accounts-header__fab"
   323→        disabled={atLimit}
   324→        onClick={openModal}
   325→      >
   326→        <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
   327→          <path d="M12 5v14M5 12h14" stroke="#fff" strokeWidth="2" strokeLinecap="round" />
   328→        </svg>
   329→      </button>
   330→
   331→      {/* Create Account Modal */}
   332→      {modalOpen && (
   333→        <Modal onClose={closeModal}>
   334→          <ModalTitle>{t('createModal.title')}</ModalTitle>
   335→
   336→          <ModalLabel>
   337→            {t('createModal.nameLabel')}
   338→            <input
   339→              ref={inputRef}
   340→              type="text"
   341→              className="modal__input"
   342→              value={accountName}
   343→              onChange={(e) => setAccountName(e.target.value)}
   344→              placeholder={t('createModal.namePlaceholder')}
   345→              maxLength={100}
   346→              disabled={creating}
   347→              onKeyDown={(e) => {
   348→                if (e.key === 'Enter') handleSubmit();
   349→                if (e.key === 'Escape') closeModal();
   350→              }}
   351→            />
   352→          </ModalLabel>
   353→
   354→          {error && <ModalError>{error}</ModalError>}
   355→
   356→          <ModalActions>
   357→            <ModalButton variant="secondary" onClick={closeModal} disabled={creating}>
   358→              {t('createModal.cancel')}
   359→            </ModalButton>
   360→            <ModalButton onClick={handleSubmit} disabled={!accountName.trim() || creating}>
   361→              {creating ? t('createModal.creating') : t('createModal.submit')}
   362→            </ModalButton>
   363→          </ModalActions>
   364→        </Modal>
   365→      )}
   366→    </>
   367→  );
   368→}
