    15→// ─── Helpers ────────────────────────────────────────────────────────────────
    16→
    17→function getAccountTotal(
    18→  account: TenantAccountBalanceSummaryDto,
    19→  currency: SalaryCurrency,
    20→): string {
    21→  switch (currency) {
    22→    case 'USD': return account.totalUSD;
    23→    case 'EUR': return account.totalEUR;
    24→    case 'RUB': return account.totalRUB;
    25→  }
    26→}
    27→
    28→function getItemBalance(item: AccountBalanceItemDto, currency: SalaryCurrency): string {
    29→  switch (currency) {
    30→    case 'USD': return item.balanceUSD;
    31→    case 'EUR': return item.balanceEUR;
    32→    case 'RUB': return item.balanceRUB;
    33→  }
    34→}
    35→
    36→function formatTotal(value: string, currency: SalaryCurrency): string {
    37→  const num = parseFloat(value);
    38→  if (isNaN(num)) return `${CURRENCY_SYMBOLS[currency]}0`;
    39→  return `${CURRENCY_SYMBOLS[currency]}${new Intl.NumberFormat('en-US', {
    40→    minimumFractionDigits: 0,
    41→    maximumFractionDigits: 0,
    42→  }).format(num)}`;
    43→}
    44→
    45→function formatBalance(value: string, decimals: number): string {
    46→  const num = parseFloat(value);
    47→  if (isNaN(num)) return '0';
    48→  return new Intl.NumberFormat('en-US', {
    49→    minimumFractionDigits: 2,
    50→    maximumFractionDigits: Math.max(2, decimals),
    51→  }).format(num);
    52→}
    53→
    54→function formatCurrencyValue(value: string, currency: SalaryCurrency): string {
    55→  const num = parseFloat(value);
    56→  if (isNaN(num)) return `${CURRENCY_SYMBOLS[currency]}0.00`;
    57→  return new Intl.NumberFormat('en-US', {
    58→    style: 'currency',
    59→    currency,
    60→    minimumFractionDigits: 2,
    61→    maximumFractionDigits: 2,
    62→  }).format(num);
    63→}
    64→
    65→function capitalize(s: string): string {
    66→  return s.charAt(0).toUpperCase() + s.slice(1);
    67→}
