    69→// ─── USDT accordion grouping ───────────────────────────────────────────────
    70→
    71→const NETWORK_INFO: Record<string, { name: string; standard: string }> = {
    72→  ethereum: { name: 'Ethereum', standard: 'ERC-20' },
    73→  tron: { name: 'Tron', standard: 'TRC-20' },
    74→  bnb: { name: 'BNB', standard: 'BEP-20' },
    75→  bsc: { name: 'BSC', standard: 'BEP-20' },
    76→};
    77→
    78→function getNetworkInfo(network: string): { name: string; standard: string } {
    79→  return NETWORK_INFO[network.toLowerCase()] ?? { name: capitalize(network), standard: '' };
    80→}
    81→
    82→function isUsdtItem(item: AccountBalanceItemDto): boolean {
    83→  return item.currencyCode.startsWith('USDT');
    84→}
    85→
    86→type DisplayItem =
    87→  | { type: 'regular'; item: AccountBalanceItemDto }
    88→  | { type: 'usdt-group'; items: AccountBalanceItemDto[] };
    89→
    90→function buildDisplayItems(balances: AccountBalanceItemDto[]): DisplayItem[] {
    91→  const usdtItems = balances.filter(isUsdtItem);
    92→  if (usdtItems.length <= 1) {
    93→    return balances.map((item) => ({ type: 'regular' as const, item }));
    94→  }
    95→
    96→  const result: DisplayItem[] = [];
    97→  let grouped = false;
    98→
    99→  for (const item of balances) {
   100→    if (isUsdtItem(item)) {
   101→      if (!grouped) {
   102→        result.push({ type: 'usdt-group', items: usdtItems });
   103→        grouped = true;
   104→      }
   105→    } else {
   106→      result.push({ type: 'regular', item });
   107→    }
   108→  }
   109→
   110→  return result;
   111→}
   112→
   113→function sumNumeric(values: string[]): number {
   114→  return values.reduce((acc, v) => acc + (parseFloat(v) || 0), 0);
   115→}
