    23→const POLL_INTERVAL_MS = 5_000;
    24→
    25→const TERMINAL_STATUSES = new Set<WithdrawalStatus>([
    26→  WithdrawalStatus.COMPLETED,
    27→  WithdrawalStatus.FAILED,
    28→]);
    29→
    30→function validateAddress(address: string, mask: string | null): boolean {
    31→  if (!mask || !address) return true;
    32→  try {
    33→    return new RegExp(mask).test(address);
    34→  } catch {
    35→    return true;
    36→  }
    37→}
    38→
    39→interface WithdrawalModalProps {
