    41→  balances: AccountBalanceItemDto[];
    42→  onClose: () => void;
    43→}
    44→
    45→export function WithdrawalModal({
    46→  tenantAccountId,
    47→  balances,
    48→  onClose,
    49→}: WithdrawalModalProps) {
    50→  const { t } = useTranslation('accounts');
    51→
    52→  const [currencyCode, setCurrencyCode] = useState(balances[0]?.currencyCode ?? '');
    53→  const [address, setAddress] = useState('');
    54→  const [amount, setAmount] = useState('');
    55→  const [submitting, setSubmitting] = useState(false);
    56→  const [error, setError] = useState('');
