    61→  const addressRef = useRef<HTMLInputElement>(null);
    62→
    63→  const selectedBalance = balances.find((b) => b.currencyCode === currencyCode);
    64→
    65→  const addressValid = validateAddress(
    66→    address.trim(),
    67→    selectedBalance?.currency.addressMask ?? null,
    68→  );
    69→
    70→  const computedMax = useMemo(() => {
    71→    if (!selectedBalance) return '0';
    72→    const bal = parseFloat(selectedBalance.balance);
    73→    if (isNaN(bal) || bal <= 0) return '0';
    74→    return maxWithdrawAmount(
    75→      bal,
    76→      selectedBalance.currency.withdrawalCommission,
    77→      selectedBalance.currency.decimalPlaces,
    78→    );
    79→  }, [selectedBalance]);
