   124→      const result = await initiateWithdrawal({
   125→        orderId: crypto.randomUUID(),
   126→        tenantAccountId,
   127→        currencyCode,
   128→        address: address.trim(),
   129→        amount: amount.trim(),
   130→      });
   131→      setWithdrawal(result);
   132→      startPolling(result.id);
   133→    } catch (err: unknown) {
   134→      const message =
   135→        err instanceof Error ? err.message : t('withdrawModal.errorGeneric');
   136→      setError(message);
   137→    } finally {
   138→      setSubmitting(false);
   139→    }
   140→  }, [currencyCode, address, amount, submitting, addressValid, tenantAccountId, startPolling, t]);
   141→
   142→  const handleMax = useCallback(() => {
   143→    setAmount(computedMax);
   144→  }, [computedMax]);
   145→
   146→  const statusLabel = (status: WithdrawalStatus) => {
