   148→      [WithdrawalStatus.CREATED]: t('withdrawModal.statusCreated'),
   149→      [WithdrawalStatus.PROCESSING]: t('withdrawModal.statusProcessing'),
   150→      [WithdrawalStatus.COMPLETED]: t('withdrawModal.statusCompleted'),
   151→      [WithdrawalStatus.FAILED]: t('withdrawModal.statusFailed'),
   152→    };
   153→    return map[status];
   154→  };
   155→
   156→  const computedFee = useMemo(() => {
   157→    if (!selectedBalance || !amount.trim()) return null;
