     1→import { create } from 'zustand';
     2→import type { AuthUser, RegistrationStep } from './types';
     3→
     4→interface SessionState {
     5→  accessToken: string | null;
     6→  refreshToken: string | null;
     7→  user: AuthUser | null;
     8→  step: RegistrationStep;
     9→}
    10→
    11→interface SessionActions {
    12→  setAuth: (payload: {
    13→    accessToken: string;
    14→    refreshToken: string;
    15→    user: AuthUser;
    16→  }) => void;
    17→  updateTokens: (accessToken: string, user: AuthUser) => void;
    18→  setStep: (step: RegistrationStep) => void;
    19→  clearAuth: () => void;
    20→}
    21→
    22→const LS_ACCESS = 'cryptonly_access_token';
    23→const LS_REFRESH = 'cryptonly_refresh_token';
    24→const LS_USER = 'cryptonly_user';
    25→
    26→function loadFromStorage(): Partial<SessionState> {
    27→  if (typeof window === 'undefined') return {};
    28→  try {
    29→    const accessToken = localStorage.getItem(LS_ACCESS);
    30→    const refreshToken = localStorage.getItem(LS_REFRESH);
    31→    const userRaw = localStorage.getItem(LS_USER);
    32→    const user = userRaw ? (JSON.parse(userRaw) as AuthUser) : null;
    33→    return { accessToken, refreshToken, user };
    34→  } catch {
    35→    return {};
    36→  }
    37→}
    38→
    39→export const useSessionStore = create<SessionState & SessionActions>((set) => ({
    40→  accessToken: null,
    41→  refreshToken: null,
    42→  user: null,
    43→  step: 1,
    44→  ...loadFromStorage(),
    45→
    46→  setAuth: ({ accessToken, refreshToken, user }) => {
    47→    if (typeof window !== 'undefined') {
    48→      localStorage.setItem(LS_ACCESS, accessToken);
    49→      localStorage.setItem(LS_REFRESH, refreshToken);
    50→      localStorage.setItem(LS_USER, JSON.stringify(user));
    51→    }
    52→    set({ accessToken, refreshToken, user });
    53→  },
    54→
    55→  updateTokens: (accessToken, user) => {
    56→    if (typeof window !== 'undefined') {
    57→      localStorage.setItem(LS_ACCESS, accessToken);
    58→      localStorage.setItem(LS_USER, JSON.stringify(user));
    59→    }
    60→    set({ accessToken, user });
    61→  },
    62→
    63→  setStep: (step) => set({ step }),
    64→
    65→  clearAuth: () => {
    66→    if (typeof window !== 'undefined') {
    67→      localStorage.removeItem(LS_ACCESS);
    68→      localStorage.removeItem(LS_REFRESH);
    69→      localStorage.removeItem(LS_USER);
    70→    }
    71→    set({ accessToken: null, refreshToken: null, user: null, step: 1 });
    72→  },
    73→}));
    74→

