    19→function buildHeaders(token?: string | null): Record<string, string> {
    20→  const headers: Record<string, string> = { 'Content-Type': 'application/json' };
    21→  if (token) headers['Authorization'] = `Bearer ${token}`;
    22→  return headers;
    23→}
    24→
    25→async function toApiError(res: Response): Promise<ApiError> {
    26→  let body: unknown;
    27→  try { body = await res.json(); } catch { body = null; }
    28→  const message =
    29→    typeof body === 'object' && body !== null &&
    30→    'message' in body && typeof (body as Record<string, unknown>).message === 'string'
    31→      ? (body as Record<string, string>).message
    32→      : `API error: ${res.status}`;
    33→  return new ApiError(res.status, body, message);
    34→}
    35→
    36→async function parseOk<T>(res: Response): Promise<T> {
    37→  if (res.status === 204) return undefined as T;
    38→  return res.json() as Promise<T>;
    39→}
    40→
    41→// ─── token refresh ────────────────────────────────────────────────────────────
    42→
    43→interface RefreshResponse { accessToken: string; user: AuthUser; }
    44→
    45→// One shared promise prevents duplicate concurrent refresh calls.
    46→let refreshingPromise: Promise<string | null> | null = null;
    47→
    48→async function tryRefresh(): Promise<string | null> {
    49→  if (refreshingPromise) return refreshingPromise;
    50→
    51→  refreshingPromise = (async (): Promise<string | null> => {
    52→    const { refreshToken, updateTokens, clearAuth } = useSessionStore.getState();
    53→    if (!refreshToken) { clearAuth(); return null; }
    54→
    55→    try {
    56→      const res = await fetch(`${BASE_URL}/public/auth/refresh`, {
    57→        method: 'POST',
    58→        headers: buildHeaders(),
    59→        body: JSON.stringify({ refreshToken }),
    60→      });
    61→      if (!res.ok) { clearAuth(); return null; }
    62→
    63→      const data: RefreshResponse = await res.json();
    64→      updateTokens(data.accessToken, data.user);
    65→      return data.accessToken;
    66→    } catch {
    67→      clearAuth();
    68→      return null;
    69→    } finally {
    70→      refreshingPromise = null;
    71→    }
    72→  })();
    73→
    74→  return refreshingPromise;
    75→}
    76→
    77→// ─── core fetch wrapper ───────────────────────────────────────────────────────
    78→
    79→async function request<T>(
    80→  method: string,
    81→  path: string,
    82→  options?: { body?: unknown; token?: string | null },
    83→): Promise<T> {
    84→  const url = `${BASE_URL}${path}`;
    85→  const serializedBody = options?.body !== undefined ? JSON.stringify(options.body) : undefined;
    86→
    87→  const token = options?.token !== undefined
    88→    ? options.token
    89→    : useSessionStore.getState().accessToken;
    90→
    91→  let res = await fetch(url, {
    92→    method,
    93→    headers: buildHeaders(token),
    94→    body: serializedBody,
    95→  });
    96→
    97→  // On 401, attempt a single token refresh then retry the original request.
    98→  // Guard against infinite loop by skipping this for the refresh endpoint itself.
    99→  if (res.status === 401 && path !== '/public/auth/refresh') {
   100→    const newToken = await tryRefresh();
   101→    if (newToken) {
   102→      res = await fetch(url, {
   103→        method,
   104→        headers: buildHeaders(newToken),
   105→        body: serializedBody,
   106→      });
   107→    }
   108→  }
   109→
   110→  if (!res.ok) throw await toApiError(res);
   111→  return parseOk<T>(res);
   112→}
   113→
   114→// ─── public API ───────────────────────────────────────────────────────────────
   115→
   116→export async function fetcher<T>(path: string): Promise<T> {
   117→  return request<T>('GET', path);
   118→}
   119→
   120→export async function post<T>(
   121→  path: string,
   122→  body?: unknown,
   123→  token?: string | null,
   124→): Promise<T> {
   125→  return request<T>('POST', path, { body, token });
   126→}
