    85→  trc20: 'TRC-20',
    86→  bep20: 'BEP-20',
    87→};
    88→
    89→const CURRENCY_DEFAULT_NETWORK: Record<string, string> = {
    90→  TRX: 'Tron',
    91→  ETH: 'Ethereum',
    92→  BTC: 'Bitcoin',
    93→  BNB: 'BNB Chain',
    94→  SOL: 'Solana',
    95→  MATIC: 'Polygon',
    96→};
    97→
    98→const FIAT_SYMBOLS: Record<string, string> = {
    99→  USD: '$',
   100→  EUR: '€',
   101→  RUB: '₽',
   102→  GBP: '£',
   103→};
   104→
   105→export function parseCurrencyDisplay(
   106→  currencyCode: string,
   107→  network?: string,
   108→): { name: string; network: string | null } {
   109→  if (network) {
   110→    const label = NETWORK_LABELS[network.toLowerCase()] ?? network;
   111→    const baseName = currencyCode.includes('_') ? currencyCode.split('_')[0] : currencyCode;
   112→    return { name: baseName, network: label };
   113→  }
   114→
   115→  const parts = currencyCode.split('_');
   116→  if (parts.length === 2) {
   117→    return { name: parts[0], network: NETWORK_LABELS[parts[1].toLowerCase()] ?? parts[1] };
   118→  }
   119→
   120→  const defaultNetwork = CURRENCY_DEFAULT_NETWORK[currencyCode] ?? null;
   121→  return { name: currencyCode, network: defaultNetwork };
   122→}
   123→
   124→export function getCurrencyDisplay(item: HistoryItem): { name: string; network: string | null } {
   125→  switch (item.type) {
   126→    case 'deposit':
   127→      return parseCurrencyDisplay(item.currencyCode, item.network);
   128→    case 'withdrawal':
   129→      return parseCurrencyDisplay(item.currencyCode);
   130→    case 'invoice':
   131→      return { name: item.fiatCurrencyCode, network: null };
   132→  }
   133→}
   134→
   135→export function getAmount(item: HistoryItem): string {
   136→  switch (item.type) {
   137→    case 'deposit':
   138→      return item.actuallyReceivedAmount != null
   139→        ? String(item.actuallyReceivedAmount)
   140→        : String(item.amountExpected);
   141→    case 'invoice':
   142→      return String(item.amount);
   143→    case 'withdrawal':
   144→      return String(item.amount);
   145→  }
   146→}
   147→
   148→export function getUsd(item: HistoryItem): string {
   149→  switch (item.type) {
   150→    case 'deposit':
   151→      return item.actuallyReceivedAmountUSD != null
   152→        ? `$${item.actuallyReceivedAmountUSD.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
   153→        : '—';
   154→    case 'invoice': {
   155→      const sym = FIAT_SYMBOLS[item.fiatCurrencyCode] ?? item.fiatCurrencyCode + ' ';
   156→      return `${sym}${item.amount.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
   157→    }
   158→    case 'withdrawal':
   159→      return `$${item.amountUsd.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
   160→  }
   161→}
   162→
   163→export function statusModifier(status: string): string {
   164→  const lower = status.toLowerCase();
   165→  if (lower === 'completed') return 'completed';
   166→  if (lower === 'deposit_pending') return 'pending';
   167→  if (lower === 'failed') return 'failed';
   168→  if (lower === 'expired') return 'expired';
   169→  if (lower === 'cancelled') return 'cancelled';
   170→  if (lower === 'processing') return 'processing';
   171→  if (lower === 'created') return 'created';
   172→  return lower;
   173→}
